import java.util.List;
import java.util.stream.Collectors;

class Order {
    private String priority;

    public Order(String priority) {
        this.priority = priority;
    }

    public String getPriority() {
        return priority;
    }

    // Method to compare two orders based on their priority
    public int compare(Order otherOrder) {
        if (this.getPriority().equals(otherOrder.getPriority())) {
            return 0;
        } else if ("high".equals(this.getPriority()) && "rush".equals(otherOrder.getPriority())) {
            return -1; // High priority comes before rush priority
        } else if ("rush".equals(this.getPriority()) && "high".equals(otherOrder.getPriority())) {
            return 1; // Rush priority comes after high priority
        } else {
            return this.getPriority().compareTo(otherOrder.getPriority());
        }
    }
}

public class Main {
    public static void main(String[] args) {
        List<Order> orders = List.of(
            new Order("high"),
            new Order("rush"),
            new Order("low")
        );

        List<Order> filteredOrders = orders.stream()
            .filter(o -> "high".equals(o.getPriority()) || "rush".equals(o.getPriority()))
            .sorted((o1, o2) -> o1.compare(o2))
            .collect(Collectors.toList());

        // Print the filtered orders
        filteredOrders.forEach(System.out::println);
    }
}
```

